"use strict";(globalThis.webpackChunkeo_glossary=globalThis.webpackChunkeo_glossary||[]).push([[7366],{76115(e){e.exports=JSON.parse('{"tag":{"label":"approved","permalink":"/eo-glossary/tags/approved","allTagsPath":"/eo-glossary/tags","count":26,"items":[{"id":"terms/accuracy","title":"Accuracy","description":"Proximity of Measurement results to the accepted Value; precision is the degree to which repeated or reproducible measurements under unchanged conditions show the same results.","permalink":"/eo-glossary/terms/accuracy"},{"id":"terms/ancillary_data","title":"Ancillary Data","description":"Data acquired on the same platform but not obtained from the main Sensor itself (usually provided as part of Level 0 Data), with the primary purpose of serving the processing of main instrument Data.","permalink":"/eo-glossary/terms/ancillary_data"},{"id":"terms/anthroposphere","title":"Anthroposphere","description":"One of the Earth spheres consisting predominantly of matter processed by humans, such as construction wood, bricks, concrete, asphalt, glass, or plastics.","permalink":"/eo-glossary/terms/anthroposphere"},{"id":"terms/archive","title":"Archive","description":"System that stores data products, guaranteeing their preservation for future use, including all operations to identify, store and retrieve the data and ensure their integrity.","permalink":"/eo-glossary/terms/archive"},{"id":"terms/area_of_interest","title":"Area of Interest","description":"Zone in 2D or 3D for which Information or Data is requested. It can be discontinuous in space, consisting of the union of many separate zones.","permalink":"/eo-glossary/terms/area_of_interest"},{"id":"terms/atmosphere","title":"Atmosphere","description":"Layer of gases, commonly known as air, including suspended liquid and solid particles known as aerosols (incl. dust, clouds, snow and ice).","permalink":"/eo-glossary/terms/atmosphere"},{"id":"terms/auxiliary_data","title":"Auxiliary Data","description":"Data that enhance the processing and utilisation of main Sensor Data, usually not captured by the same Data collection Process or on the same platform as the main Sensor Data.","permalink":"/eo-glossary/terms/auxiliary_data"},{"id":"terms/backup","title":"Backup","description":"General practice of making copies of current baseline and derived products of EO Collections at specified time intervals, storing those copies in a manner that will not affect the data if the primary distribution environment is compromised.","permalink":"/eo-glossary/terms/backup"},{"id":"terms/band_central_wavelength","title":"Band Central Wavelength","description":"Single wavelength Value within the sensitivity interval of a spectroradiometric Sensor which represents the respective band. It could be the mean, median, maximum sensitivity, or any other reasonable representative Value.","permalink":"/eo-glossary/terms/band_central_wavelength"},{"id":"terms/baseline","title":"Baseline","description":"Reference Period, time or measure against which Information is assessed or compared.","permalink":"/eo-glossary/terms/baseline"},{"id":"terms/biosphere","title":"Biosphere","description":"Masses of living organisms, such as vegetation and animals, including dead but still connected parts such as roots, trunks or branches.","permalink":"/eo-glossary/terms/biosphere"},{"id":"terms/business_continuity","title":"Business Continuity","description":"An organisation\'s readiness to continue functioning during times of disruption.","permalink":"/eo-glossary/terms/business_continuity"},{"id":"terms/calibration","title":"Calibration","description":"Process of quantitatively defining a system\'s (e.g. a Sensor or Model\'s) response to known, controlled inputs produced by references. In Remote Sensing, implies the collection of pre-flight and in-flight calibration measurements and in-situ Data.","permalink":"/eo-glossary/terms/calibration"},{"id":"terms/catalogue","title":"Catalogue","description":"System that provides users with discovery of information on which EO products can be obtained.","permalink":"/eo-glossary/terms/catalogue"},{"id":"terms/cell","title":"Cell","description":"Spatial, spatio-temporal zone or temporal unit of geometry with dimensionality greater than 0, associated with a zone.","permalink":"/eo-glossary/terms/cell"},{"id":"terms/characteristic","title":"Characteristic","description":"Distinguishing Feature of an object or entity, which can be inherent or assigned, and qualitative or quantitative.","permalink":"/eo-glossary/terms/characteristic"},{"id":"terms/classification_system","title":"Classification System","description":"Nomenclature used to classify Information into categorical thematic classes (e.g., EUNIS, MAES ecosystems, Corine Land Cover, LCCS).","permalink":"/eo-glossary/terms/classification_system"},{"id":"terms/classification_system_levels","title":"Classification System Levels","description":"Levels in a hierarchical Classification System.","permalink":"/eo-glossary/terms/classification_system_levels"},{"id":"terms/climate_projection","title":"Climate Projection","description":"Simulated response of the climate system to a scenario of future emission or concentration of greenhouse gases (GHGs) and aerosols, generally derived using climate models.","permalink":"/eo-glossary/terms/climate_projection"},{"id":"terms/collection","title":"Collection","description":"Group of products that have been processed using a consistent radiometric calibration, geometric registration base, data/metadata format, and version of processing algorithms.","permalink":"/eo-glossary/terms/collection"},{"id":"terms/collection_update","title":"Collection Update","description":"Minor revisions to a relatively small number of products within a collection for the purpose of correcting errors and maintaining consistent quality.","permalink":"/eo-glossary/terms/collection_update"},{"id":"terms/collection_upgrade","title":"Collection Upgrade","description":"New and improved major version of all products within a collection due to comprehensive reprocessing.","permalink":"/eo-glossary/terms/collection_upgrade"},{"id":"terms/confidence_interval","title":"Confidence Interval","description":"Probability that a Quantity lies in a given interval, conditioned on the measuring or modelling assumptions.","permalink":"/eo-glossary/terms/confidence_interval"},{"id":"terms/copernicus_service_provider","title":"Copernicus Service Provider","description":"Institutional body, organisation or programme that provides reliable, trusted EO Information and has the financial resources to sustain the provision.","permalink":"/eo-glossary/terms/copernicus_service_provider"},{"id":"terms/coverage_interval","title":"Coverage Interval","description":"Range or specific subset of values associated with a coverage dataset.","permalink":"/eo-glossary/terms/coverage_interval"},{"id":"terms/cryosphere","title":"Cryosphere","description":"Masses of frozen water, such as sea ice, ice shields, glaciers, and snow.","permalink":"/eo-glossary/terms/cryosphere"}],"unlisted":false}}')}}]);